mapper.select:
select
    id,
    tenant_id,
    file_id,
    operation_type,
    operation_result,
    operator_type,
    operator_id,
    trace_id,
    evidence_ref,
    detail_summary,
    created_at
from batch.file_audit_log
where tenant_id = #{tenantId}

    and operation_type = #{operationType}


    and trace_id = #{traceId}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}

order by id desc


    limit #{pageRequest.pageSize}
    offset #{offset}

select count(1)
from batch.file_audit_log
where tenant_id = #{tenantId}

    and operation_type = #{operationType}


    and trace_id = #{traceId}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}
